import React from 'react';
import { Button } from 'primereact/button';

const WishlistFilters = ({ 
  wishlistSort, 
  setWishlistSort, 
  onCreateWishlist, 
  showCreateButton = true 
}) => {
  return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1rem', width: '100%' }}>
      <div style={{ position: 'relative', minWidth: '280px', maxWidth: '500px' }}>
        <i 
          className="pi pi-sort-alt" 
          style={{ 
            position: 'absolute', 
            left: '12px', 
            top: '50%', 
            transform: 'translateY(-50%)', 
            fontSize: '16px', 
            color: '#1e293b',
            pointerEvents: 'none',
            zIndex: 1
          }}
        />
        <select
          value={wishlistSort}
          onChange={e => setWishlistSort(e.target.value)}
          style={{ 
            fontSize: '14px', 
            padding: '0 40px 0 40px', 
            borderRadius: '12px', 
            border: '2px solid #18B700',
            color: '#1e293b',
            width: '100%',
            height: '40px',
            lineHeight: '40px',
            appearance: 'none',
            WebkitAppearance: 'none',
            backgroundImage: 'url("/images/path.svg")',
            backgroundRepeat: 'no-repeat',
            backgroundPosition: 'right 12px center',
            backgroundSize: '9px 5px',
            cursor: 'pointer',
            outline: 'none',
            backgroundColor: '#fff',
            fontFamily: 'inherit',
          }}
        >
          <option value="createdAt_desc">По дате добавления</option>
          <option value="createdAt_asc">По дате создания (старые)</option>
          <option value="title_asc">По алфавиту (А–Я)</option>
          <option value="title_desc">По алфавиту (Я–А)</option>
          <option value="eventDate_asc">По дате события (ближайшие)</option>
          <option value="eventDate_desc">По дате события (дальние)</option>
        </select>
      </div>
      {showCreateButton && (
        <Button
          label="Создать вишлист"
          icon="pi pi-plus"
          onClick={onCreateWishlist}
          className="custom-green-button"
        />
      )}
    </div>
  );
};

export default WishlistFilters;
